import { HttpErrorResponse } from "@angular/common/http";
import { Component, OnInit } from "@angular/core";
import { FormBuilder, FormGroup } from "@angular/forms";
import { IscoreExportedFileList } from "src/app/core/models/IScore/IscoreExportedFileList";
import { AlertService } from "src/app/core/services/alert.service";
import { BranchService } from "src/app/core/services/branch.service";
import { IscoreHttpService } from "src/app/core/services/iscore-http.service";
import { LoansService } from "src/app/core/services/loans.service";
import { pagingService } from "src/app/core/services/paging.service";
import { ReferencesService } from "src/app/core/services/references.service";
import { IClientType } from "src/app/views/Models/Client/ClientType";
import { LoanTypeRef } from "src/app/views/Models/Loan/LoanType";
import { Funders } from "src/app/views/Models/References/Funders";
import { StaticRef } from "src/app/views/Models/References/StaticRef";
import { BranchReference } from "src/app/views/Models/Settings/BranchReference";
import { saveAs } from "file-saver";
import { IscoreExportedFileDataRequest } from "src/app/core/models/IScore/IscoreExportedFileDataRequest";

@Component({
  selector: "app-download-iscore-files",
  templateUrl: "./download-iscore-files.page.html",
  styleUrls: ["./download-iscore-files.page.scss"],
})
export class DownloadIscoreFilesPage implements OnInit {
  //#region Flags
  showLoader: boolean = false;
  showModal: boolean = false;
  //#endregion
  //#region Variables
  page: number = 1;
  IscoreExportedFilesList: IscoreExportedFileList[];
  branches: BranchReference[];
  disabledBranches: string[];
  funders: Funders[];
  disabledFunders: string[];
  clientTypes: IClientType[];
  disabledClientTypes: string[];
  loanTypes: LoanTypeRef[];
  disabledLoanTypes: string[];
  loanTypeCat: StaticRef[];
  iscoreReportType: StaticRef[];
  months: StaticRef[];
  selectedIscoreEcportedFile: IscoreExportedFileList = null;
  selectedMonth: number;
  //#endregion
  //#region Forms
  formGroup: FormGroup = this.formBuilder.group({
    branchId: [null],
    funderId: [null],
    clientTypeId: [null],
    loanTypeId: [null],
    loanTypeCategoryId: [null],
  });
  //#endregion

  constructor(
    public iscoreService: IscoreHttpService,
    public pagingService: pagingService,
    private branchService: BranchService,
    private referenceService: ReferencesService,
    private loanService: LoansService,
    private formBuilder: FormBuilder,
    public alertService: AlertService
  ) {}

  async ngOnInit() {
    this.showLoader = true;
    this.branches = await this.branchService.getBranches();
    this.disabledBranches = this.branches.map((branch) => branch.branch_code);
    this.funders = await this.referenceService.getAllFunders();
    this.disabledFunders = this.funders.map((funder) => funder.funder_code);
    this.clientTypes = await this.referenceService.GetClientTypes();
    this.disabledClientTypes = this.clientTypes.map(
      (clientType) => clientType.client_type_code
    );
    this.loanTypes = await this.loanService.getLoanTypes();
    this.disabledLoanTypes = this.loanTypes.map(
      (loanType) => loanType.loan_type_code
    );
    this.loanTypeCat = await this.referenceService.getLoanTypeCategories();
    this.iscoreReportType = await this.referenceService
      .getIScoreReportType()
      .toPromise();
    this.months = await this.referenceService.getMonths().toPromise();
    this.iscoreService.getIscoreExportedFileList().subscribe(
      (data) => {
        this.IscoreExportedFilesList = data;
        this.showLoader = false;
      },
      (error) => {
        console.log(error);
        this.showLoader = false;
      }
    );
  }

  changePage(newPage: number): void {
    this.page = newPage;
  }

  openOptionsModal(iscoreExportedFile: IscoreExportedFileList) {
    this.selectedIscoreEcportedFile = iscoreExportedFile;
    this.formGroup.patchValue({
      funderId: iscoreExportedFile.ls_fund,
      branchId: iscoreExportedFile.ls_branch,
      clientTypeId: iscoreExportedFile.ls_client_type,
      loanTypeId: iscoreExportedFile.ls_loan_type,
    });
    let date = new Date(iscoreExportedFile.period_start_date);
    this.selectedMonth = date.getMonth() + 1;
    this.showModal = true;
  }

  closeOptionsModal() {
    this.selectedIscoreEcportedFile = null;
    this.selectedMonth = null;
    this.showModal = false;
  }
  async downloadFile(batchId: string, fileType: number, fileName: string) {
    try {
      this.showLoader = true;
      let request: IscoreExportedFileDataRequest = {
        batchId: Number(batchId),
        fileType: fileType,
      };
      let file = await this.iscoreService
        .getIscoreExportedFileData(request)
        .toPromise();
      await this.downloadingFile(file, fileName);
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }

  async downloadingFile(file: any, fileName: string) {
    const cleanedContent = file.replace(/^details_content\s*\r?\n/, "");
    let blob = new Blob([cleanedContent], { type: "application/octet-stream" });
    await saveAs(
      blob,
      fileName.endsWith(".dlt") ? fileName : `${fileName}.dlt`
    );
  }

  private handleError(error: unknown) {
    const errorMessage =
      error instanceof HttpErrorResponse
        ? JSON.stringify(error.error)
        : error instanceof Error
        ? error.message
        : String(error);

    this.alertService.showAlertError(errorMessage, false);
    console.error("Error:", error);
  }
}
